import { Database } from "bun:sqlite";
import { mkdirSync } from "fs";
var DB_FOLDER = "./storage/db";
var DB_PATH = `${DB_FOLDER}/app.db`;

class RecordingRepository {
  db;
  constructor() {
    mkdirSync(DB_FOLDER, { recursive: true });
    this.db = new Database(DB_PATH);
    this.init();
  }
  init() {
    this.db.run(`
      CREATE TABLE IF NOT EXISTS recordings (
        id TEXT PRIMARY KEY,
        title TEXT,
        duration REAL,
        createdAt TEXT,
        filePath TEXT
      )
    `);
  }
  async create(recording) {
    const query = this.db.prepare(`
      INSERT INTO recordings (id, title, duration, createdAt, filePath)
      VALUES ($id, $title, $duration, $createdAt, $filePath)
    `);
    query.run({
      $id: recording.id,
      $title: recording.title,
      $duration: recording.duration,
      $createdAt: recording.createdAt,
      $filePath: recording.filePath
    });
  }
  async findAll() {
    return this.db.query("SELECT * FROM recordings").all();
  }
  async findById(id) {
    return this.db.query("SELECT * FROM recordings WHERE id = ?").get(id);
  }
  async delete(id) {
    this.db.run("DELETE FROM recordings WHERE id = ?", [id]);
  }
}

